import{c as a}from"./app.8935f5f1.js";const n={},t=a('<h2 id="freemarker配置文件" tabindex="-1"><a class="header-anchor" href="#freemarker配置文件" aria-hidden="true">#</a> freeMarker配置文件</h2><div class="language-properties ext-properties"><pre class="language-properties"><code>\n<span class="token comment">## Spring Boot  For Freemarker </span>\n<span class="token attr-name">spring.freemarker.template-loader-path</span><span class="token punctuation">=</span><span class="token attr-value">classpath:/templates </span>\n<span class="token attr-name">spring.freemarker.cache</span><span class="token punctuation">=</span><span class="token attr-value">false </span>\n<span class="token attr-name">spring.freemarker.charset</span><span class="token punctuation">=</span><span class="token attr-value">UTF-8 </span>\n<span class="token attr-name">spring.freemarker.check-template-location</span><span class="token punctuation">=</span><span class="token attr-value">true </span>\n<span class="token attr-name">spring.freemarker.content-type</span><span class="token punctuation">=</span><span class="token attr-value">text/html </span>\n<span class="token attr-name">spring.freemarker.expose-request-attributes</span><span class="token punctuation">=</span><span class="token attr-value">false </span>\n<span class="token attr-name">spring.freemarker.expose-session-attributes</span><span class="token punctuation">=</span><span class="token attr-value">false </span>\n<span class="token attr-name">spring.freemarker.request-context-attribute</span><span class="token punctuation">=</span><span class="token attr-value">request </span>\n<span class="token attr-name">spring.freemarker.suffix</span><span class="token punctuation">=</span><span class="token attr-value">.ftl</span>\n\n\n</code></pre></div><div class="language-yaml ext-yml"><pre class="language-yaml"><code><span class="token key atrule">server</span><span class="token punctuation">:</span>\n  <span class="token key atrule">port</span><span class="token punctuation">:</span> <span class="token number">8889</span>\n<span class="token key atrule">mybatis</span><span class="token punctuation">:</span>\n  <span class="token key atrule">type-aliases-package</span><span class="token punctuation">:</span> com.sys.log.domain\n  <span class="token key atrule">mapper-locations</span><span class="token punctuation">:</span> classpath<span class="token punctuation">:</span>mapper/<span class="token important">*.xml</span>\n<span class="token key atrule">spring</span><span class="token punctuation">:</span>\n  <span class="token key atrule">application</span><span class="token punctuation">:</span>\n    <span class="token key atrule">name</span><span class="token punctuation">:</span> hystory<span class="token punctuation">-</span>server\n  <span class="token key atrule">datasource</span><span class="token punctuation">:</span>\n    <span class="token key atrule">type</span><span class="token punctuation">:</span> com.zaxxer.hikari.HikariDataSource\n    <span class="token key atrule">driver-class-name</span><span class="token punctuation">:</span> com.mysql.jdbc.Driver\n    <span class="token key atrule">url</span><span class="token punctuation">:</span> jdbc<span class="token punctuation">:</span>mysql<span class="token punctuation">:</span>///security<span class="token punctuation">?</span>useUnicode=true<span class="token important">&amp;characterEncoding=utf-8&amp;useSSL=false</span>\n    <span class="token key atrule">username</span><span class="token punctuation">:</span> root\n    <span class="token key atrule">password</span><span class="token punctuation">:</span> <span class="token number">0</span>\n    <span class="token key atrule">hikari</span><span class="token punctuation">:</span>\n      <span class="token key atrule">minimum-idle</span><span class="token punctuation">:</span> <span class="token number">5</span>\n      <span class="token key atrule">idle-timeout</span><span class="token punctuation">:</span> <span class="token number">600000</span>\n      <span class="token key atrule">maximum-pool-size</span><span class="token punctuation">:</span> <span class="token number">10</span>\n      <span class="token key atrule">auto-commit</span><span class="token punctuation">:</span> <span class="token boolean important">true</span>\n      <span class="token key atrule">pool-name</span><span class="token punctuation">:</span> MyHikariCP\n      <span class="token key atrule">max-lifetime</span><span class="token punctuation">:</span> <span class="token number">1800000</span>\n      <span class="token key atrule">connection-timeout</span><span class="token punctuation">:</span> <span class="token number">30000</span>\n      <span class="token key atrule">connection-test-query</span><span class="token punctuation">:</span> SELECT 1\n      <span class="token comment">#配置 freemarker 文件路径和文件后缀</span>\n  <span class="token key atrule">freemarker</span><span class="token punctuation">:</span>\n    <span class="token key atrule">suffix</span><span class="token punctuation">:</span> .html\n    <span class="token key atrule">template-loader-path</span><span class="token punctuation">:</span> classpath<span class="token punctuation">:</span>/templates/\n<span class="token key atrule">logging</span><span class="token punctuation">:</span>\n  <span class="token key atrule">level</span><span class="token punctuation">:</span>\n    <span class="token key atrule">com.sys.log.mapper</span><span class="token punctuation">:</span> DEBUG\n</code></pre></div><h2 id="freemarker模板文件" tabindex="-1"><a class="header-anchor" href="#freemarker模板文件" aria-hidden="true">#</a> FreeMarker模板文件</h2><ul><li>主要有4个部分组成： （1）文本，直接输出的部分 （2）注释，即&lt;#--...--&gt;格式不会输出 （3）插值(Interpolation)：即${..}或者#{..}格式的部分，将使用数据模型中的部分替代输出 （4）FTL指令：FreeMarker指令，和HTML标记类似，名字前加#予以区分，不会输出。</li></ul><div class="language-html ext-html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span> \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>  \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>#--</span> <span class="token attr-name">注释部分</span> <span class="token attr-name">--</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>br</span><span class="token punctuation">&gt;</span></span>  \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>#--</span> <span class="token attr-name">下面使用插值</span> <span class="token attr-name">--</span><span class="token punctuation">&gt;</span></span>  \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>Welcome ${user} !<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span>We have these animals:\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>u1</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>#--</span> <span class="token attr-name">使用FTL指令</span> <span class="token attr-name">--</span><span class="token punctuation">&gt;</span></span>  \n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>#list</span> <span class="token attr-name">animals</span> <span class="token attr-name">as</span> <span class="token attr-name">being</span><span class="token punctuation">&gt;</span></span>\n　　<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span><span class="token punctuation">&gt;</span></span>${being.name} <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>#list</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>u1</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>\n\n</code></pre></div><p>*<strong>1*</strong>|*<strong>1*<strong><strong>1. 指令</strong></strong>（1）list 指令</strong></p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#list nameList as names&gt;    \n  ${names}   \n&lt;/#list&gt;\n</code></pre></div><p>主要是进行迭代服务器端传递过来的List集合，name 是 list 循环的时候取的一个循环变量。相关指令：</p><p>item_index：当前变量的索引值 item_has_next：是否存在下一个对象 break：跳出迭代</p><p><strong>（2）if 指令</strong></p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#if name == &quot;freemarker&quot;&gt;\n  freemarker 模板引擎\n&lt;/#if&gt;\n</code></pre></div><div class="language-text ext-text"><pre class="language-text"><code>&lt;#assign number1 = 8&gt;\n&lt;#assign number2 = 5&gt;\n&lt;#if (number1 + number2 &gt; 12 || number1 - number2 &gt; 6)&gt;\n    &quot;*&quot; : ${number1 * number2}\n&lt;#else&gt;\n    &quot;/&quot; : ${number1 / number2}\n&lt;/#if&gt;\n</code></pre></div><div class="language-text ext-text"><pre class="language-text"><code>&lt;#if users??&gt;  &lt;#--空判断--&gt;\n    &lt;#list users as user &gt;\n        ${user.id} - ${user.name}\n    &lt;/#list&gt;\n&lt;#else&gt;\n    ${user!&quot;变量为空则给一个默认值&quot;}\n&lt;/#if&gt;\n</code></pre></div><p><strong>（3）include 指令</strong></p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#include filename&gt;\n&lt;#include filename options&gt;\n</code></pre></div><p>该标签用于导入文件。option包含下面2种属性：</p><p>encoding=&quot;GBK&quot; 编码格式 parse=true 是否作为ftl语法解析，默认是 true，false 就是以文本方式引入。注意在ftl文件里布尔值都是直接赋值的如 parse=true，而不是 parse=&quot;true&quot;</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#include &quot;include.html&quot;/&gt;  \n&lt;#include &quot;include.ftl&quot; encoding=&quot;GBK&quot;/&gt;\n&lt;#include &quot;/common/copyright.ftl&quot; encoding=&quot;GBK&quot; parse=false/&gt;\n</code></pre></div><p><strong>（4）switch , case , default , break 指令</strong></p><p>语法：</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#switch value&gt;\n    &lt;#case refValue&gt;语句1&lt;#break&gt;\n    &lt;#case refValue&gt;语句2&lt;#break&gt;\n    &lt;#default&gt;语句3\n&lt;/#switch&gt;\n</code></pre></div><p>示例：</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#switch name&gt;\n    &lt;#case &quot;freemarker&quot;&gt;This is a freemarker&#39;s template.&lt;#break&gt;\n    &lt;#case &quot;velocity&quot;&gt;This is a velocity&#39;s template.&lt;#break&gt;\n    &lt;#default&gt;This is a jsp&#39;s template.\n&lt;/#switch&gt;\n</code></pre></div><p><strong>（5）macro 宏指令</strong></p><p>定义宏：</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#macro mo&gt;\n    定义无参数的宏macro--${name}\n&lt;/#macro&gt;\n</code></pre></div><div class="language-text ext-text"><pre class="language-text"><code>&lt;#macro moArgs a b c&gt;\n    定义带参数的宏macro--${a+b+c}\n&lt;/#macro&gt;\n</code></pre></div><p>调用宏：</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;@mo /&gt;\n</code></pre></div><div class="language-text ext-text"><pre class="language-text"><code>&lt;@moArgs a=1 b=2 c=3 /&gt;\n</code></pre></div><p><strong>（6）import 指令</strong></p><p>类似于java里的 import，它导入文件，然后就可以在当前文件里使用被导入文件里的宏组件。</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#import path as hash&gt;\n</code></pre></div><p>path：文件路径</p><p>hash：为导入的文件定义命名空间</p><p><strong>（7）assign 指令</strong></p><p>assign指令用于为该模板页面创建或替换一个顶层变量。</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#assign a=1&gt;\n&lt;#assign x=1 y=2&gt;\n</code></pre></div><div class="language-text ext-text"><pre class="language-text"><code>&lt;#assign arg1&gt;\n    hello freemarker\n&lt;/#assign&gt;\n\n&lt;#assign arg2&gt;\n    ${arg1} world\n&lt;/#assign&gt;\n\n&lt;#assign arg3=&quot;${arg1} world&quot;&gt;\n</code></pre></div><p><strong>（8）noparse 指令</strong></p><p>noparse指令指定FreeMarker不处理该指定里包含的内容。</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#assign a=1&gt;\n&lt;#noparse&gt;\n    ${a}\n&lt;/#noparse&gt;\n\n输出结果：\n${a}\n</code></pre></div><p><strong>（9）setting 指令</strong></p><div class="language-text ext-text"><pre class="language-text"><code>&lt;#setting name=value&gt;\n</code></pre></div><p>该指令用于设置FreeMarker的运行环境,name的取值范围包含如下几个：</p><p>locale：该选项指定该模板所用的国家/语言选项</p><p>number_format：指定格式化输出数字的格式</p><p>boolean_format：指定两个布尔值的语法格式,默认值是true,false</p><p>date_format，time_format，datetime_format：指定格式化输出日期的格式</p><p>time_zone：设置格式化输出日期时所使用的时区</p><p>*<strong>2*</strong>|***0***<strong>二、示例</strong></p><div class="language-text ext-text"><pre class="language-text"><code>字符串输出:\n${&quot;Hello ${name} !&quot;} / ${&quot;Hello &quot; + name + &quot; !&quot;}\n&lt;#assign cname=r&quot;特殊字符完成输出(http:\\www.baidu.com)&quot;&gt;\n${cname}\n\n字符串截取 ： \n通过下标直接获取下标对应的字母： ${name[2]}\n起点下标..结尾下标截取字符串：${name[0..5]}\n\n算数运算：\n&lt;#-- 支持&quot;+&quot;、&quot;－&quot;、&quot;*&quot;、&quot;/&quot;、&quot;%&quot;运算符 --&gt;\n&lt;#assign number1 = 10&gt;\n&lt;#assign number2 = 5&gt;\n&quot;+&quot; : ${number1 + number2}\n&quot;－&quot; : ${number1 - number2}\n&quot;*&quot; : ${number1 * number2}\n&quot;/&quot; : ${number1 / number2}\n&quot;%&quot; : ${number1 % number2}\n\n比较运算符：\n&lt;#if number1 + number2 gte 12 || number1 - number2 lt 6&gt;\n&quot;*&quot; : ${number1 * number2}\n&lt;#else&gt;\n&quot;/&quot; : ${number1 / number2}\n&lt;/#if&gt;\n\n内建函数：\n&lt;#assign data = &quot;abcd1234&quot;&gt;\n第一个字母大写：${data?cap_first}\n所有字母小写：${data?lower_case}\n所有字母大写：${data?upper_case}\n&lt;#assign floatData = 12.34&gt;\n数值取整数：${floatData?int}\n获取集合的长度：${users?size}\n时间格式化：${dateTime?string(&quot;yyyy-MM-dd&quot;)}\n\n空判断和对象集合：\n&lt;#if users??&gt;\n&lt;#list users as user &gt;\n${user.id} - ${user.name}\n&lt;/#list&gt;\n&lt;#else&gt;\n${user!&quot;变量为空则给一个默认值&quot;}\n&lt;/#if&gt;\n\nMap集合：\n&lt;#assign mapData={&quot;name&quot;:&quot;程序员&quot;, &quot;salary&quot;:15000}&gt;\n直接通过Key获取 Value值：${mapData[&quot;name&quot;]}\n通过Key遍历Map：\n&lt;#list mapData?keys as key&gt;\nKey: ${key} - Value: ${mapData[key]}\n&lt;/#list&gt;\n通过Value遍历Map：\n&lt;#list mapData?values as value&gt;\nValue: ${value}\n&lt;/#list&gt;\n\nList集合：\n&lt;#assign listData=[&quot;ITDragon&quot;, &quot;blog&quot;, &quot;is&quot;, &quot;cool&quot;]&gt;\n&lt;#list listData as value&gt;${value} &lt;/#list&gt;\n\ninclude指令：\n引入其他文件：&lt;#include &quot;otherFreeMarker.ftl&quot; /&gt;\n\nmacro宏指令：\n&lt;#macro mo&gt;\n定义无参数的宏macro--${name}\n&lt;/#macro&gt;\n使用宏macro: &lt;@mo /&gt;\n&lt;#macro moArgs a b c&gt;\n定义带参数的宏macro-- ${a+b+c}\n&lt;/#macro&gt;\n使用带参数的宏macro: &lt;@moArgs a=1 b=2 c=3 /&gt;\n\n命名空间：\n&lt;#import &quot;otherFreeMarker.ftl&quot; as otherFtl&gt;\n${otherFtl.otherName}\n&lt;@otherFtl.addMethod a=10 b=20 /&gt;\n&lt;#assign otherName=&quot;修改otherFreeMarker.ftl中的otherName变量值&quot;/&gt;\n${otherFtl.otherName}\n&lt;#assign otherName=&quot;修改otherFreeMarker.ftl中的otherName变量值&quot; in otherFtl /&gt;\n${otherFtl.otherName}\n</code></pre></div>',53);n.render=function(a,n){return t};export{n as default};
